import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
import requests
from io import BytesIO
import os

class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

def download_model_from_url(url):
    response = requests.get(url)
    response.raise_for_status()
    return torch.load(BytesIO(response.content), map_location=torch.device('cpu'))

def fine_tune_model(model, train_loader, val_loader, num_epochs=5, learning_rate=1e-4):
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    model.to(device)
    
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    for epoch in range(num_epochs):
        model.train()
        running_loss = 0.0
        for inputs, labels in train_loader:
            inputs, labels = inputs.to(device), labels.to(device)
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            running_loss += loss.item()
        
        model.eval()
        correct = 0
        total = 0
        with torch.no_grad():
            for inputs, labels in val_loader:
                inputs, labels = inputs.to(device), labels.to(device)
                outputs = model(inputs)
                _, predicted = torch.max(outputs, 1)
                total += labels.size(0)
                correct += (predicted == labels).sum().item()
        
        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {running_loss/len(train_loader):.4f}, Accuracy: {100*correct/total:.2f}%')
    
    return model

# Example usage
if __name__ == "__main__":
    # Download model
    model_url = "https://example.com/pretrained_model.pth"
    model = download_model_from_url(model_url)
    
    # Prepare custom dataset
    custom_data = torch.randn(1000, 3, 224, 224)
    custom_labels = torch.randint(0, 10, (1000,))
    dataset = CustomDataset(custom_data, custom_labels)
    
    # Split dataset
    train_size = int(0.8 * len(dataset))
    val_size = len(dataset) - train_size
    train_dataset, val_dataset = torch.utils.data.random_split(dataset, [train_size, val_size])
    
    train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
    val_loader = DataLoader(val_dataset, batch_size=32, shuffle=False)
    
    # Fine-tune model
    fine_tuned_model = fine_tune_model(model, train_loader, val_loader)
    
    # Save fine-tuned model
    torch.save(fine_tuned_model.state_dict(), 'fine_tuned_model.pth')